71	      JSON.stringify({
72	        expandedProjectCwds: state.projects
73	          .filter((project) => project.expanded)
74	          .map((project) => project.cwd),
75	      }),
76	    );
77	    for (const legacyKey of LEGACY_PERSISTED_STATE_KEYS) {
78	      window.localStorage.removeItem(legacyKey);
79	    }
80	  } catch {
81	    // Ignore quota/storage errors to avoid breaking chat UX.
82	  }
83	}
