/**
 * Theme type definitions for T3 Code.
 *
 * This module is intentionally free of DOM/React dependencies — it contains
 * only static data and pure type/value helpers consumed by any renderer surface.
 */

/** Identifier for a built-in application theme. */
export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/**
 * Surface-specific color tokens for a named theme.
 * All values are valid CSS color strings (hex, oklch, …) suitable for
 * swatch previews and inline-style attributes.
 */
export interface ThemeColors {
  /** Main application background */
  background: string;
  /** Primary text / foreground */
  foreground: string;
  /** Accent / primary interactive color */
  accent: string;
  /** Sidebar panel background */
  sidebar: string;
  /** Sidebar foreground text */
  sidebarForeground: string;
  /** Code editor area background */
  editor: string;
  /** Code editor foreground text */
  editorForeground: string;
  /** Terminal (xterm) background */
  terminal: string;
  /** Status bar background */
  statusBar: string;
  /** Status bar foreground text */
  statusBarForeground: string;
}

/** Metadata and representative preview colors for a built-in theme. */
export interface BuiltInTheme {
  readonly id: ThemeId;
  readonly label: string;
  readonly description: string;
  /**
   * Determines the CSS `color-scheme` and whether dark-mode utility classes
   * are activated for this theme.
   */
  readonly colorScheme: "light" | "dark";
  /**
   * Representative color values used for swatch previews in the UI.
   * The authoritative styles are applied via `:root[data-theme]` blocks in
   * `index.css`.
   */
  readonly colors: ThemeColors;
}

/** All built-in themes shipped with T3 Code. */
export const BUILT_IN_THEMES: readonly BuiltInTheme[] = [
  {
    id: "t3-dark",
    label: "T3 Dark",
    description: "The default dark experience with a blue accent.",
    colorScheme: "dark",
    colors: {
      background: "#0a0a0f",
      foreground: "#f5f5f5",
      accent: "#6366f1",
      sidebar: "#0f0f16",
      sidebarForeground: "#a1a1aa",
      editor: "#09090e",
      editorForeground: "#e4e4e7",
      terminal: "#060609",
      statusBar: "#0d0d14",
      statusBarForeground: "#71717a",
    },
  },
  {
    id: "t3-light",
    label: "T3 Light",
    description: "A clean light theme for bright environments.",
    colorScheme: "light",
    colors: {
      background: "#ffffff",
      foreground: "#1a1a2e",
