/** Identifier for a built-in application theme. */
export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/**
 * Surface-specific color tokens for a named theme.
 * All values are valid CSS color strings (hex, oklch, …) suitable for
 * swatch previews and inline-style attributes.
 */
export interface ThemeColors {
  /** Main application background */
  background: string;
  /** Primary text / foreground */
  foreground: string;
  /** Accent / primary interactive color */
  accent: string;
  /** Sidebar panel background */
  sidebar: string;
  /** Sidebar foreground text */
  sidebarForeground: string;
  /** Code editor area background */
