import { useCallback, useSyncExternalStore } from "react";
import {
  DEFAULT_THEME_ID,
  getThemeById,
  isThemeId,
  type ThemeId,
} from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:theme-id";

let listeners: Array<() => void> = [];

function emitChange() {
  for (const listener of listeners) listener();
}

export function getStoredThemeId(): ThemeId {
  const raw = localStorage.getItem(STORAGE_KEY);
  return isThemeId(raw) ? raw : DEFAULT_THEME_ID;
}

/**
 * Applies a theme by setting the `data-theme` attribute and toggling the
 * `.dark` class on `<html>`. Optionally suppresses CSS transitions to avoid
 * a flash when switching themes.
 */
export function applyTheme(id: ThemeId, suppressTransitions = false): void {
  const theme = getThemeById(id);
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  document.documentElement.setAttribute("data-theme", id);
  document.documentElement.classList.toggle("dark", theme.colorScheme === "dark");
  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply the stored theme immediately on module load to prevent FOUC.
applyTheme(getStoredThemeId());

function getSnapshot(): ThemeId {
  return getStoredThemeId();
}

function getServerSnapshot(): ThemeId {
  return DEFAULT_THEME_ID;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Sync theme changes from other browser tabs.
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStoredThemeId(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export interface ThemeContextValue {
  /** The active named theme identifier. */
  themeId: ThemeId;
  /** Persists and applies a new theme. */
  setThemeId: (id: ThemeId) => void;
  /**
   * The resolved color scheme of the active theme.
   * Always `"light"` or `"dark"` — never `"system"`.
   */
  resolvedTheme: "light" | "dark";
}

export function useTheme(): ThemeContextValue {
  const themeId = useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
  const resolvedTheme = getThemeById(themeId).colorScheme;

  const setThemeId = useCallback((next: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  return { themeId, setThemeId, resolvedTheme };
}

