import { createContext, useContext, type ReactNode } from "react";
import { useTheme as useThemeStore, type ThemeContextValue } from "../hooks/useTheme";

const ThemeContext = createContext<ThemeContextValue | null>(null);

/**
 * Provides theme state to the component tree via React Context.
 *
 * Place this high in the render tree (e.g., in the root route layout) so that
 * all descendants share a single subscription to the theme store.
 */
export function ThemeProvider({ children }: { children: ReactNode }) {
  const value = useThemeStore();
  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

/**
 * Returns the active theme state and a setter for changing it.
 *
 * Falls back to the module-level external store when called outside a
 * {@link ThemeProvider}, so existing call-sites remain functional during
 * incremental adoption.
 */
export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  // When a provider is present, use its value (shared subscription).
  // When not, fall back to a direct store read so the hook always works.
  if (ctx !== null) return ctx;
  // eslint-disable-next-line react-hooks/rules-of-hooks -- intentional fallback
  return useThemeStore();
}

