import { createContext, useContext, type ReactNode } from "react";
import { useTheme as useThemeStore, type ThemeContextValue } from "../hooks/useTheme";

const ThemeContext = createContext<ThemeContextValue | null>(null);

/**
 * Provides theme state to the component tree via React Context so that all
 * descendants share a single subscription to the underlying theme store.
 *
 * Place this high in the render tree (e.g., in the root route layout).
 * Components that call {@link useTheme} do not strictly require this provider
 * — they fall back to the module-level store — but wrapping with
 * `ThemeProvider` is the recommended pattern for consistent state sharing.
 */
export function ThemeProvider({ children }: { children: ReactNode }) {
  const value = useThemeStore();
  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

/**
 * Returns the active theme state and a setter for changing it.
 *
 * When called inside a {@link ThemeProvider} the context value is returned
 * (single shared subscription). When called outside a provider the hook
 * subscribes directly to the module-level store so it always works regardless
 * of provider placement.
 */
export function useTheme(): ThemeContextValue {
  // Always subscribe to the store for cases where no provider is in the tree.
  // When a provider is present the context value shadows this.
  const storeValue = useThemeStore();
  const ctx = useContext(ThemeContext);
  return ctx ?? storeValue;
}

