import { CheckIcon } from "lucide-react";
import { BUILT_IN_THEMES, type ThemeId } from "@t3tools/shared/theme";
import { cn } from "~/lib/utils";
import { useTheme } from "./ThemeProvider";

interface ThemeSelectorProps {
  className?: string;
}

/**
 * Grid of clickable theme cards with swatch previews.
 * Reads and updates the active theme via {@link useTheme}.
 */
export function ThemeSelector({ className }: ThemeSelectorProps) {
  const { themeId, setThemeId } = useTheme();

  return (
    <div
      role="radiogroup"
      aria-label="Theme"
      className={cn("grid grid-cols-1 gap-3 sm:grid-cols-3", className)}
    >
      {BUILT_IN_THEMES.map((theme) => {
        const selected = themeId === theme.id;
        const { colors } = theme;

        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setThemeId(theme.id as ThemeId)}
            className={cn(
              "group relative flex flex-col gap-2.5 rounded-xl border p-3 text-left transition-colors",
              "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:ring-offset-background",
              selected
                ? "border-primary/60 bg-primary/8"
                : "border-border bg-background hover:bg-accent/50",
            )}
          >
            {/* Swatch preview */}
            <div
              aria-hidden="true"
              className="relative h-[4.5rem] w-full overflow-hidden rounded-lg"
              style={{ background: colors.background }}
            >
              {/* Sidebar strip */}
              <div
                className="absolute inset-y-0 left-0 w-8"
                style={{ background: colors.sidebar }}
              />

              {/* Editor area */}
              <div
                className="absolute inset-y-0 left-8 right-0"
                style={{ background: colors.editor }}
              >
                {/* Simulated code lines */}
                <div className="absolute left-2 top-2.5 flex flex-col gap-1">
                  <div
                    className="h-1.5 w-12 rounded-full opacity-50"
                    style={{ background: colors.accent }}
                  />
                  <div
                    className="h-1.5 w-16 rounded-full opacity-20"
                    style={{ background: colors.editorForeground }}
                  />
                  <div
                    className="h-1.5 w-10 rounded-full opacity-20"
                    style={{ background: colors.editorForeground }}
                  />
                  <div
                    className="h-1.5 w-14 rounded-full opacity-15"
                    style={{ background: colors.editorForeground }}
                  />
                </div>
              </div>

              {/* Terminal bar */}
              <div
                className="absolute inset-x-0 bottom-[0.35rem] h-4"
                style={{ background: colors.terminal }}
              />

              {/* Status bar */}
              <div
                className="absolute inset-x-0 bottom-0 h-[0.35rem]"
                style={{ background: colors.statusBar }}
              />

              {/* Sidebar sidebar items simulation */}
              <div className="absolute left-1 top-2 flex flex-col gap-1">
                <div
                  className="h-1 w-5 rounded-full opacity-30"
                  style={{ background: colors.sidebarForeground }}
                />
                <div
                  className="h-1 w-4 rounded-full opacity-20"
                  style={{ background: colors.sidebarForeground }}
                />
                <div
                  className="h-1 w-5 rounded-full opacity-20"
                  style={{ background: colors.sidebarForeground }}
                />
              </div>

              {/* Accent dot (top-right) */}
              <div
                className="absolute right-2 top-2 size-2.5 rounded-full"
                style={{ background: colors.accent }}
              />

              {/* Selected overlay */}
              {selected && (
                <div className="absolute inset-0 flex items-center justify-center bg-black/15">
                  <span
                    className="flex size-5 items-center justify-center rounded-full shadow-sm"
                    style={{ background: colors.accent }}
                  >
                    <CheckIcon className="size-3 text-white" strokeWidth={3} />
                  </span>
                </div>
              )}
            </div>

            {/* Theme label + badge */}
            <div className="flex items-start justify-between gap-2">
              <div className="min-w-0">
                <p
                  className={cn(
                    "text-sm font-medium leading-tight",
                    selected ? "text-foreground" : "text-muted-foreground group-hover:text-foreground",
                  )}
                >
                  {theme.label}
                </p>
                <p className="mt-0.5 text-xs leading-snug text-muted-foreground">
                  {theme.description}
                </p>
              </div>
              {selected && (
                <span className="mt-px shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-semibold uppercase tracking-wide text-primary">
                  Active
                </span>
              )}
            </div>
          </button>
        );
      })}
    </div>
  );
}

