/* ==========================================================================
   Named theme overrides
   Applied via `data-theme` attribute on <html> by the theme store.

   Each selector uses `:root[data-theme="…"]` which carries specificity
   [0,2,0] — equal to `:root.dark` produced by @variant dark above.
   Because these blocks appear later in the file they win via cascade order,
   fully owning all colour tokens for the selected theme.

   Additionally, `.dark` is toggled on <html> for dark themes so that
   Tailwind's `dark:` utility classes and dark-scrollbar rules keep working.
   ========================================================================== */

/* ── T3 Dark ── */
:root[data-theme="t3-dark"] {
  color-scheme: dark;
  --background: #0a0a0f;
  --foreground: #f5f5f5;
  --card: #0e0e15;
  --card-foreground: #f5f5f5;
  --popover: #0e0e15;
  --popover-foreground: #f5f5f5;
  --primary: oklch(0.588 0.217 264);
  --primary-foreground: #ffffff;
  --secondary: rgb(255 255 255 / 0.04);
  --secondary-foreground: #f5f5f5;
  --muted: rgb(255 255 255 / 0.04);
  --muted-foreground: #a1a1aa;
  --accent: rgb(255 255 255 / 0.04);
  --accent-foreground: #f5f5f5;
  --destructive: #ef4444;
  --destructive-foreground: #f87171;
  --border: rgb(255 255 255 / 0.06);
  --input: rgb(255 255 255 / 0.08);
  --ring: oklch(0.588 0.217 264);
  --info: #3b82f6;
  --info-foreground: #60a5fa;
  --success: #10b981;
  --success-foreground: #34d399;
  --warning: #f59e0b;
  --warning-foreground: #fbbf24;
  /* Surface-specific tokens */
  --theme-sidebar: #0f0f16;
  --theme-sidebar-foreground: #a1a1aa;
  --theme-editor: #09090e;
  --theme-editor-foreground: #e4e4e7;
  --theme-terminal: #060609;
  --theme-statusbar: #0d0d14;
  --theme-statusbar-foreground: #71717a;
}

/* ── T3 Light ── */
:root[data-theme="t3-light"] {
  color-scheme: light;
  --background: #ffffff;
  --foreground: #1a1a2e;
  --card: #ffffff;
  --card-foreground: #1a1a2e;
  --popover: #ffffff;
  --popover-foreground: #1a1a2e;
  --primary: oklch(0.488 0.217 264);
  --primary-foreground: #ffffff;
  --secondary: rgb(0 0 0 / 0.04);
  --secondary-foreground: #1a1a2e;
  --muted: rgb(0 0 0 / 0.04);
  --muted-foreground: #52525b;
  --accent: rgb(0 0 0 / 0.04);
  --accent-foreground: #1a1a2e;
  --destructive: #ef4444;
  --destructive-foreground: #b91c1c;
  --border: rgb(0 0 0 / 0.08);
  --input: rgb(0 0 0 / 0.10);
  --ring: oklch(0.488 0.217 264);
  --info: #3b82f6;
  --info-foreground: #1d4ed8;
  --success: #10b981;
  --success-foreground: #047857;
  --warning: #f59e0b;
  --warning-foreground: #92400e;
  /* Surface-specific tokens */
  --theme-sidebar: #f4f4fb;
  --theme-sidebar-foreground: #52525b;
  --theme-editor: #fafafa;
  --theme-editor-foreground: #18181b;
  --theme-terminal: #1a1a2e;
  --theme-statusbar: #eeeef8;
  --theme-statusbar-foreground: #6b7280;
}

/* ── T3 Midnight ── */
:root[data-theme="t3-midnight"] {
  color-scheme: dark;
  --background: #04040a;
  --foreground: #e2e2f0;
  --card: #070710;
  --card-foreground: #e2e2f0;
  --popover: #070710;
  --popover-foreground: #e2e2f0;
  --primary: oklch(0.62 0.25 280);
  --primary-foreground: #ffffff;
  --secondary: rgb(255 255 255 / 0.03);
  --secondary-foreground: #e2e2f0;
  --muted: rgb(255 255 255 / 0.03);
  --muted-foreground: #8b8ba8;
  --accent: rgb(255 255 255 / 0.03);
  --accent-foreground: #e2e2f0;
  --destructive: #ef4444;
  --destructive-foreground: #f87171;
  --border: rgb(255 255 255 / 0.05);
  --input: rgb(255 255 255 / 0.07);
  --ring: oklch(0.62 0.25 280);
  --info: #3b82f6;
  --info-foreground: #60a5fa;
  --success: #10b981;
  --success-foreground: #34d399;
  --warning: #f59e0b;
  --warning-foreground: #fbbf24;
  /* Surface-specific tokens */
  --theme-sidebar: #06060f;
  --theme-sidebar-foreground: #8b8ba8;
  --theme-editor: #020208;
  --theme-editor-foreground: #d4d4f0;
  --theme-terminal: #010106;
  --theme-statusbar: #07070f;
  --theme-statusbar-foreground: #6b6b8a;
}

