/* ── T3 Dark ─────────────────────────────────────────────────────────────── */
:root[data-theme="t3-dark"] {
  color-scheme: dark;
  --background: #0a0a0f;
  --foreground: #f5f5f5;
  --card: #0e0e15;
  --card-foreground: #f5f5f5;
  --popover: #0e0e15;
  --popover-foreground: #f5f5f5;
