  --secondary: rgb(255 255 255 / 0.03);
  --secondary-foreground: #e2e2f0;
  --muted: rgb(255 255 255 / 0.03);
  --muted-foreground: #8b8ba8;
  --accent: rgb(255 255 255 / 0.03);
  --accent-foreground: #e2e2f0;
  --destructive: #ef4444;
  --destructive-foreground: #f87171;
  --border: rgb(255 255 255 / 0.05);
  --input: rgb(255 255 255 / 0.07);
  --ring: oklch(0.62 0.25 280);
  --info: #3b82f6;
  --info-foreground: #60a5fa;
  --success: #10b981;
  --success-foreground: #34d399;
  --warning: #f59e0b;
  --warning-foreground: #fbbf24;
  --theme-sidebar: #06060f;
  --theme-sidebar-foreground: #8b8ba8;
